"use client"
import { useState } from "react"

export default function Page() {

  // MASTER LISTEN
  const [items, setItems] = useState<any[]>([])
  const [vehicles, setVehicles] = useState<any[]>([])

  // LAGER (fahrzeuge mit inhalt)
  const [storage, setStorage] = useState<any[]>([])

  // FORM ITEM
  const [itemForm, setItemForm] = useState({ name: "", image: "" })

  // FORM VEHICLE
  const [vehicleForm, setVehicleForm] = useState({
    name: "",
    image: "",
    plate: "",
    location: "",
    note: ""
  })

  // AUSWAHL
  const [selectedVehicle, setSelectedVehicle] = useState("")
  const [selectedItem, setSelectedItem] = useState("")
  const [amount, setAmount] = useState("")

  const [openVehicle, setOpenVehicle] = useState<any>(null)

  // IMAGE UPLOAD → BASE64
  const handleImageUpload = (e: any, setFunc: any, form: any) => {
    const file = e.target.files[0]
    const reader = new FileReader()

    reader.onloadend = () => {
      setFunc({ ...form, image: reader.result })
    }

    if (file) reader.readAsDataURL(file)
  }

  // CREATE ITEM
  const createItem = () => {
    if (!itemForm.name) return
    setItems([...items, { ...itemForm, id: Date.now() }])
    setItemForm({ name: "", image: "" })
  }

  // CREATE VEHICLE
  const createVehicle = () => {
    if (!vehicleForm.name) return
    setVehicles([...vehicles, { ...vehicleForm, id: Date.now() }])
    setVehicleForm({ name: "", image: "", plate: "", location: "", note: "" })
  }

  // ADD VEHICLE TO STORAGE
  const addVehicleToStorage = () => {
    const v = vehicles.find(v => v.id.toString() === selectedVehicle)
    if (!v) return

    if (storage.find(s => s.id === v.id)) return

    setStorage([...storage, { ...v, inventory: [] }])
  }

  // ADD ITEM TO VEHICLE
  const addItemToVehicle = () => {
    const item = items.find(i => i.id.toString() === selectedItem)

    setStorage(storage.map(v => {
      if (v.id.toString() !== selectedVehicle) return v

      const existing = v.inventory.find((i: any) => i.id === item.id)

      if (existing) {
        existing.amount = Number(existing.amount) + Number(amount)
      } else {
        v.inventory.push({ ...item, amount })
      }

      return { ...v }
    }))

    setAmount("")
  }

  return (
    <main className="min-h-screen bg-[#070707] text-white p-10">

      <h1 className="text-5xl font-bold mb-12">
        <span className="text-white">Storage</span>{" "}
        <span className="text-purple-400">System</span>
      </h1>

      {/* ITEM CREATOR */}
      <div className="mb-16">
        <h2 className="text-xl mb-3">🔫 Item erstellen</h2>

        <input
          placeholder="Name"
          value={itemForm.name}
          onChange={e => setItemForm({ ...itemForm, name: e.target.value })}
          className="bg-black/40 p-3 rounded mb-2"
        />

        <input type="file"
          onChange={(e) => handleImageUpload(e, setItemForm, itemForm)}
        />

        <button onClick={createItem} className="bg-purple-500 px-4 py-2 mt-2 rounded">
          Erstellen
        </button>
      </div>

      {/* VEHICLE CREATOR */}
      <div className="mb-16">
        <h2 className="text-xl mb-3">🚗 Fahrzeug erstellen</h2>

        <input placeholder="Name"
          value={vehicleForm.name}
          onChange={e => setVehicleForm({ ...vehicleForm, name: e.target.value })}
          className="bg-black/40 p-3 rounded mb-2"
        />

        <input type="file"
          onChange={(e) => handleImageUpload(e, setVehicleForm, vehicleForm)}
        />

        <input placeholder="Kennzeichen"
          value={vehicleForm.plate}
          onChange={e => setVehicleForm({ ...vehicleForm, plate: e.target.value })}
          className="bg-black/40 p-3 rounded mb-2"
        />

        <input placeholder="Standort"
          value={vehicleForm.location}
          onChange={e => setVehicleForm({ ...vehicleForm, location: e.target.value })}
          className="bg-black/40 p-3 rounded mb-2"
        />

        <input placeholder="Notiz"
          value={vehicleForm.note}
          onChange={e => setVehicleForm({ ...vehicleForm, note: e.target.value })}
          className="bg-black/40 p-3 rounded mb-2"
        />

        <button onClick={createVehicle} className="bg-purple-500 px-4 py-2 rounded">
          Erstellen
        </button>
      </div>

      {/* STORAGE CONTROL */}
      <div className="mb-16">
        <h2 className="text-xl mb-3">📦 Lager verwalten</h2>

        <select onChange={e => setSelectedVehicle(e.target.value)} className="bg-black p-2 mr-2">
          <option>Fahrzeug wählen</option>
          {vehicles.map(v => (
            <option key={v.id} value={v.id}>{v.name}</option>
          ))}
        </select>

        <button onClick={addVehicleToStorage} className="bg-purple-500 px-3 py-2 rounded">
          Fahrzeug ins Lager
        </button>

        <div className="mt-4">
          <select onChange={e => setSelectedItem(e.target.value)} className="bg-black p-2 mr-2">
            <option>Item wählen</option>
            {items.map(i => (
              <option key={i.id} value={i.id}>{i.name}</option>
            ))}
          </select>

          <input placeholder="Anzahl"
            value={amount}
            onChange={e => setAmount(e.target.value)}
            className="bg-black p-2 mr-2"
          />

          <button onClick={addItemToVehicle} className="bg-purple-500 px-3 py-2 rounded">
            Item zuweisen
          </button>
        </div>
      </div>

      {/* STORAGE VIEW */}
      <div className="grid md:grid-cols-3 gap-6">

        {storage.map(v => (
          <div key={v.id}
            onClick={() => setOpenVehicle(v)}
            className="cursor-pointer border border-white/10 rounded-xl p-4 bg-white/[0.03]">

            <img src={v.image} className="h-40 w-full object-cover rounded mb-3" />

            <h3>{v.name}</h3>
            <p className="text-sm text-zinc-400">{v.plate}</p>
          </div>
        ))}

      </div>

      {/* INVENTORY VIEW */}
      {openVehicle && (
        <div className="fixed inset-0 bg-black/90 flex justify-center items-center">

          <div className="bg-[#111] p-6 rounded-xl w-[600px]">

            <h2 className="text-2xl mb-2">{openVehicle.name}</h2>
            <p className="text-sm text-zinc-400 mb-4">
              {openVehicle.plate} · {openVehicle.location}
            </p>

            <div className="grid grid-cols-3 gap-4">

              {openVehicle.inventory.map((item: any, i: number) => (
                <div key={i} className="text-center">
                  <img src={item.image} className="h-20 w-full object-cover rounded mb-1" />
                  <div className="text-purple-400">{item.amount}</div>
                </div>
              ))}

            </div>

            <button
              onClick={() => setOpenVehicle(null)}
              className="mt-6 bg-red-500 px-4 py-2 rounded"
            >
              Schließen
            </button>

          </div>

        </div>
      )}

    </main>
  )
}
